/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;
    if (N === 0) return [];

    // --- Step 1: Precalculate closest(x) ---
    const C = new Array(N);
    for (let x = 0; x < N; x++) {
        if (x === 0) {
            C[x] = 1;
            continue;
        }
        if (x === N - 1) {
            C[x] = N - 2;
            continue;
        }

        const diffL = Math.abs(nums[x] - nums[x - 1]);
        const diffR = Math.abs(nums[x] - nums[x + 1]);

        if (diffL < diffR) {
            C[x] = x - 1;
        } else if (diffR < diffL) {
            C[x] = x + 1;
        } else {
            // Tie, choose smaller index
            C[x] = x - 1;
        }
    }

    // --- Priority Queue implementation (Min Heap) ---
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        size() {
            return this.heap.length;
        }

        // Compares based on distance (d)
        _compare(i, j) {
            return this.heap[i].d < this.heap[j].d;
        }

        _swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        _bubbleUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this._compare(index, parentIndex)) {
                    this._swap(index, parentIndex);
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }

        _bubbleDown(index) {
            const lastIndex = this.heap.length - 1;
            while (true) {
                let leftChildIndex = 2 * index + 1;
                let rightChildIndex = 2 * index + 2;
                let smallest = index;

                if (leftChildIndex <= lastIndex && this._compare(leftChildIndex, smallest)) {
                    smallest = leftChildIndex;
                }
                if (rightChildIndex <= lastIndex && this._compare(rightChildIndex, smallest)) {
                    smallest = rightChildIndex;
                }

                if (smallest !== index) {
                    this._swap(index, smallest);
                    index = smallest;
                } else {
                    break;
                }
            }
        }

        enqueue(d, index) {
            this.heap.push({ d, index });
            this._bubbleUp(this.heap.length - 1);
        }

        dequeue() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this._bubbleDown(0);
            return min;
        }
    }

    // --- Step 2: Process Queries using Dijkstra's Algorithm ---
    const results = [];

    for (const query of queries) {
        const L = query[0];
        const R = query[1];

        if (L === R) {
            results.push(0);
            continue;
        }

        // Dijkstra Initialization
        const INF = Number.MAX_SAFE_INTEGER;
        const dist = new Array(N).fill(INF);
        const pq = new PriorityQueue();

        dist[L] = 0;
        pq.enqueue(0, L);

        let minCost = INF;

        while (!pq.isEmpty()) {
            const { d: currentDist, index: x } = pq.dequeue();

            if (currentDist > dist[x]) {
                continue;
            }

            if (x === R) {
                minCost = currentDist;
                break; 
            }

            // Optimization: If we found a path to R, we can potentially stop early 
            // if we are sure Dijkstra guarantees shortest path first, but we continue 
            // to ensure we explore all paths potentially better than the current minCost.

            // --- Relaxation Step ---

            // 1. Type 2 Move: Move to closest(x)
            const y_closest = C[x];
            const cost2 = 1;
            if (currentDist + cost2 < dist[y_closest]) {
                dist[y_closest] = currentDist + cost2;
                pq.enqueue(dist[y_closest], y_closest);
            }

            // 2. Type 1 Move: Move to ANY index y
            // This step is O(N) and makes the total complexity O(N^2) per query.
            // This is necessary to model the problem fully, despite performance concerns for N=10^5.

            for (let y = 0; y < N; y++) {
                if (x === y) continue;

                // Cost = |nums[x] - nums[y]|
                const cost1 = Math.abs(nums[x] - nums[y]);

                if (currentDist + cost1 < dist[y]) {
                    dist[y] = currentDist + cost1;
                    pq.enqueue(dist[y], y);
                }
            }
        }

        results.push(dist[R]);
    }

    return results;
}

